public void testArgumentsWithProperties() {
  collapsePropertiesOnExternTypes = true;
  testSame(
    "function f() {\n" +
    "  var args = arguments;\n" +
    "  args.length;\n" +
    "  return args;\n" +
    "}\n");
}

public void testNestedFunctionWithArgumentsAlias() {
  collapsePropertiesOnExternTypes = true;
  testSame(
    "function outer() {\n" +
    "  function inner() {\n" +
    "    var a = arguments;\n" +
    "    return function() { return a[0]; };\n" +
    "  }\n" +
    "  return inner;\n" +
    "}\n");
}

public void testArgumentsAliasWithMultipleRefs() {
  collapsePropertiesOnExternTypes = true;
  testSame(
    "function f() {\n" +
    "  var args = arguments;\n" +
    "  alert(args);\n" +
    "  setTimeout(function() { alert(args); }, 0);\n" +
    "}\n");
}
